# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

from flask import Flask, redirect, request, session
import requests

app = Flask(__name__)

# Configure OpenID Connect client
client_id = "your-client-id"
client_secret = "your-client-secret"
authorization_url = "https://example.com/oauth/authorize"
token_url = "https://example.com/oauth/token"
jwks_uri = "https://example.com/.well-known/openid-configuration/jwks"
redirect_uri = "http://localhost:5000/callback"

@app.route("/")
def index():
    # Redirect to authorization URL
    return redirect(authorization_url + "?response_type=code&client_id=" + client_id + "&redirect_uri=" + redirect_uri)

@app.route("/callback", methods=["GET"])
def callback():
    # Exchange authorization code for tokens
    response = requests.post(token_url, data={"grant_type": "authorization_code", "code": request.args["code"], "redirect_uri": redirect_uri, "client_id": client_id, "client_secret": client_secret})
    
    # Decode id_token and extract user claims
    id_token = response.json()["id_token"]
    claims = requests.get(jwks_uri + "/" + id_token).json()["claims"]
    
    # Store user information in session
    session["user_info"] = { "name": claims["name"], "email": claims["email"] }
    
    # Redirect to dashboard page
    return redirect("/dashboard")

@app.route("/dashboard", methods=["GET"])
def dashboard():
    user_info = session.get("user_info")
    if user_info:
        name = user_info["name"]
        email = user_info["email"]
        return "Welcome, %s (%s)!" % (name, email)
    else:
        return "You are not logged in."